insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (223, '가칭 개포주공아파트 A어린이집 위탁체 선정', NULL, '<p>안녕하세요.</p><p>비영리민간단체 자람 입니다.</p><p>&nbsp;</p><p>강남구 국공립 개포주공 1단지 A어린이집으로 선정 되었습니다.</p><p>&nbsp;</p><p>회원님들의 덕분 입니다.</p><p>&nbsp;</p>', NULL, 18, 'notice', false, NULL, false, 'k0421jm@naver.com', '권정문', '2023-11-15 07:23:55.000', '2023-11-15 07:23:55.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (224, '미래인재양성초등학생로봇코딩교육안내', NULL, '<p>안녕하세요. 일원 1동 청소년 지도 협의회 회장 정수연입니다.<br>2023년의 마지막 4차산업과 관련된 교육을 진행하고자 하니 관내 학부모님들의 많은 성원 부탁드립니다!</p><p><br>4차산업 미래인재 양성 초등학생 로봇코딩 교육 참가자 모집합니다</p><p>가. 교육개요<br>• 교육주제: 4차산업 미래인재 양성교육(부제: Creative 코딩! K-POP로봇댄스 창작하라)<br>• 교육대상 : 일원1동 관내 초등학교 4-6학년<br>• 교육장소: 일원1동주민센터 3층 대강당(양재대로55길 14)<br>• 모집민원: 각 반별 15명 x4개반(총60명) / 11.18(호), 11.25(로) 2회 교육 참석 필수<br>• 교육방법: 이론 및 실습 00분씩 총2회<br>• 교육내용: MIT에서 개발한 코딩교육 소프트웨어Scratch를 기반으로 로봇을 제어구동<br>함으로써 코딩결과들 실제로 확인하여 문제들 해결하는 프로젝트 교육<br>• 교육비용: 무료(학생준비물: 필기도구)<br>• 교육일정<br>• 신청기간: 11.16.(목) 18:00까지<br>• 참여방법: 신청서 이메일 제출 / 선착순 배정<br>- 제출 이메일: youth. guidance.council@gmail.com<br>- 상담 및 문의: 정수연(일원1동 청소년지도협의회장) 010-3391-4404<br>※ 대상 학정은 개별 문자안내 예정<br>#로봇코딩 #4차산업 #청소년지도협의회</p>', NULL, 15, 'notice', false, NULL, false, 'k0421jm@naver.com', '권정문', '2023-11-15 08:04:03.000', '2023-11-15 08:04:03.000');
