insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (227, '2023년 일원에코문화마을', '친환경스토리', '<p>2023년 지역특화 분과 참여 활동 보고</p><ul><li>참여자 : 하숙자/권정문/최영숙/김희덕/김정은/손유림/박현정/송정현(재능기부 )</li></ul><p>&nbsp; <img class="image_resized" style="width:41.16%;" src="/ckeditor/upload/2023/11/15/d2a918dd-8504-4c8c-8b2a-8bfaf6f9cef8.jpg"></p>', '/ckeditor/upload/2023/11/15/d2a918dd-8504-4c8c-8b2a-8bfaf6f9cef8.jpg', 5, 'gallery', false, NULL, false, 'k0421jm@naver.com', '권정문', '2023-11-15 14:14:13.000', '2023-11-25 10:27:18.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (228, '24년 수능 대박 나세요.', NULL, '<p>오늘은 2023년11월16일 목요일</p><p>수능 고사장에 다녀 왔습니다.</p><p>(자유총연맹과 함께----응원 합니다.)</p>', NULL, 8, 'notice', false, NULL, false, 'k0421jm@naver.com', '권정문', '2023-11-16 10:25:12.000', '2023-11-16 10:25:12.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (229, '비영리단체자람 수능 응원', '24학년도 수능 응원', '<ul><li>24학년도 수능을 응원합니다.</li><li>7년후 꼬마 친구들과 함께 했습니다.</li></ul><figure class="image image_resized" style="width:49.29%;"><img src="/ckeditor/upload/2023/11/16/283f623e-8f0d-4c87-861c-bbf4552de4a9.jpg"></figure>', '/ckeditor/upload/2023/11/16/283f623e-8f0d-4c87-861c-bbf4552de4a9.jpg', 6, 'gallery', false, NULL, false, 'k0421jm@naver.com', '권정문', '2023-11-16 10:32:13.000', '2023-11-25 10:28:24.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (230, '2023년 일원 주민환경체험', '강남자원회수시설', '<p>2023년 일원에코 문화 마을 축제 가을이야기</p><figure class="image image_resized" style="width:55.71%;"><img src="/ckeditor/upload/2023/11/16/d482ad8a-4c34-424a-8cd0-ee8fe865f534.jpg"></figure>', '/ckeditor/upload/2023/11/16/d482ad8a-4c34-424a-8cd0-ee8fe865f534.jpg', 10, 'gallery', false, NULL, false, 'k0421jm@naver.com', '권정문', '2023-11-16 10:34:25.000', '2023-11-25 10:27:58.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (231, '비영리민간단체 설립취지', '설립취지', '<p>설립취지</p><p>&nbsp;</p><p>○&nbsp;안심하고 맡길 보육 환경 조성과 초등 돌봄의 사각지대 해소</p><p>&nbsp;-&nbsp;학부모,&nbsp;교사,&nbsp;원장,&nbsp;지역인사,&nbsp; &nbsp;마을활동가,&nbsp;전문가의 구성으로 안심하고 맡길</p><p>&nbsp;보육환경,&nbsp;사회적 경력 단절의 위기를 극복하도록 돕고,&nbsp;함께 운영하는 국 공립 직장 보육시설,&nbsp; 초등 돌봄의 위탁 사업 지원</p><p>&nbsp;</p><p>&nbsp;○&nbsp;민&nbsp;․&nbsp;관 협력형 자람 프로그램 개발&nbsp;(지역맞춤 연계,공익활동 지원사업) &nbsp;</p><p>&nbsp;</p><figure class="image"><img src="/ckeditor/upload/2023/11/16/16e768ac-7a25-4c7c-b44a-6605a21992e6.jpg"></figure><p>&nbsp;</p><p>&nbsp;</p>', '/ckeditor/upload/2023/11/16/16e768ac-7a25-4c7c-b44a-6605a21992e6.jpg', 16, 'news', false, NULL, false, 'k0421jm@naver.com', '권정문', '2023-11-16 12:35:16.000', '2023-11-16 12:35:16.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (232, '설립배경', '설립배경', '<figure class="table"><table style="border:0.28pt solid #000000;"><tbody><tr><td style="border-bottom-style:dotted;border-color:#000000;border-left-style:solid;border-right-style:dotted;border-top-style:dotted;border-width:0.28pt;height:108.82pt;padding:1.41pt 5.10pt;width:85.30pt;"><p style="text-align:center;">설립 배경</p></td><td style="border-bottom-style:dotted;border-color:#000000;border-left-style:dotted;border-right-style:solid;border-top-style:dotted;border-width:0.28pt;height:108.82pt;padding:1.41pt 5.10pt;width:368.30pt;"><p><span style="color:#0000ff;"><i>-&nbsp;</i></span>사회적인 필요성에 의해서(엄마 아빠 행복 프로젝트&nbsp;)자주적·&nbsp;자립적·&nbsp;자치적인 회원 활동을 통 하여 건강한 지역 사회 보육 서비스를 제공하며,지역 공동체의 아동권리존중 향상에이바지하기 위하여 &nbsp;100명이상의 회원이모여 양질의 영유아어린이집 어린이집&nbsp;,초등돌봄 위탁 목적으로함 &nbsp;</p><p>-&nbsp;서울시,강남구를 중심으로 환경의 지키기의 대기환경,기후위기대응</p><p>&nbsp;나무심기의 친환경 만들기 참여(내가 먼저 실천하기)</p><p>&nbsp;-&nbsp;소외계층발굴 및 지원을 위한 사업 만들기</p></td></tr></tbody></table></figure><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><figure class="image image_resized" style="width:24.42%;"><img src="https://seoul-jaram.com/ckeditor/upload/2023/11/16/97971344-2028-4008-944f-8bb3a38b8484.jpg"></figure><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p>', '/ckeditor/upload/2023/11/16/97971344-2028-4008-944f-8bb3a38b8484.jpg', 22, 'news', false, NULL, false, 'k0421jm@naver.com', '권정문', '2023-11-16 12:56:04.000', '2023-12-28 08:06:57.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (234, '2024년 희망온돌 따듯한겨울나기', NULL, '<p>2024년 희망온돌 따듯한 겨울나기에 함께 해주세요.<img class="image_resized" style="width:16.47%;" src="/ckeditor/upload/2023/11/24/49d8ea68-bda8-4900-9b68-fe3b531b7f41.jpg"></p>', NULL, 13, 'notice', false, NULL, false, 'k0421jm@naver.com', '권정문', '2023-11-24 11:40:04.000', '2023-11-25 10:21:42.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (235, 'test', 'test', '<p>test<img class="image_resized" style="width:26.69%;" src="/ckeditor/upload\\2023\\11\\27/ec3a46c6-3545-420f-a058-b5501545ac58.png"></p>', '/ckeditor/upload\\2023\\11\\27/ec3a46c6-3545-420f-a058-b5501545ac58.png', 1, 'gallery', false, NULL, true, 'io1027@naver.com', '김성민', '2023-11-27 09:06:05.000', '2023-11-27 09:06:29.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (238, '2024년 희망 온돌 따뜻한 겨울나기', '비영리민간 단체 자람 활동', '<p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p style="text-align:center;"><mark class="marker-blue"><strong>2024년 비영리 민간 단체 홍보대사 활동</strong></mark></p><figure class="image image_resized" style="width:38.65%;"><img src="/ckeditor/upload/2023/11/27/eb7a72d4-c7b9-41e5-b9fd-729b340dbbdd.jpg"></figure><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p>', '/ckeditor/upload/2023/11/27/eb7a72d4-c7b9-41e5-b9fd-729b340dbbdd.jpg', 6, 'gallery', false, NULL, false, 'k0421jm@naver.com', '권정문', '2023-11-27 16:18:10.000', '2023-11-27 16:18:10.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (239, '대표소개', NULL, '<p>안녕하십니까?</p><p>비영리 민간 단체 자람 대표 권 정문 입니다.</p><p>&nbsp;</p><p>자람은</p><p>104명의 회원님들의 생각을 함께 모아서 설립한 단체 입니다.</p><p>&nbsp;</p><p>자람은 다음과 같은 목표를 실천 하고 자 합니다.</p><p>&nbsp;</p><p>○&nbsp;안심하고 맡길 보육 환경 조성과 초등 돌봄의 사각지대 해소</p><p>&nbsp;-&nbsp;학부모,&nbsp;교사,&nbsp;원장,&nbsp;지역 인사,&nbsp;마을 활동가 ,&nbsp;전문가의 구성으로 안심하고 맡길 보육 환경,&nbsp;사회적 경력 단절의 위기를 극복하도록 돕고,&nbsp;함께 운영하는 국 공립 직장 보육시설,&nbsp; 초등 돌봄의 위탁 사업 지원</p><p>&nbsp;</p><p>&nbsp;○&nbsp;민&nbsp;․&nbsp;관 협력 형 자람 프로그램 개발 &nbsp;( 지역맞춤 연계, 공익활동 지원사업)</p><p>&nbsp;</p><p>회원님들과 함께, 회원님들의 소중한 꿈을 이루어 가는 민간단체자람이</p><p>되도록 하겠습니다.</p><p>&nbsp;</p><p>&nbsp;</p>', NULL, 0, 'ceo', false, NULL, false, NULL, NULL, '2023-11-28 09:13:36.000', '2023-11-28 09:13:36.000');
