insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (261, '설립취지문', NULL, '<p>설립취지문</p><p>-</p>', NULL, 0, 'esta', false, NULL, false, NULL, NULL, '2023-12-08 15:44:14.000', '2023-12-13 15:37:30.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (262, '설립취지문', NULL, '<p><strong>[비영리민간단체 자람 &nbsp;연혁보고]</strong></p><p>&nbsp;</p><ul><li>비영리민간단체 자람은 1994년 보육현장과 연계 지역활동을 시작 했습니다.(기반다지기)</li><li>2004년부터는 임의단체로 공익활동/주민참여예산/환경학교활동을 시작함(본격적인활동다지기)</li><li>2023년2월22일 비영리 민간단체 자람 서울시영유아담당관에서 등록함</li><li>2023년10월에 14일 강남구청에 서 구립 퍼스티어고운어린이집을 위탁계약함</li><li>2024.8.14 &nbsp;강남 9호점 수서역세권 다함께 (가칭) 키움 위탁 체결</li><li><mark class="marker-blue">2025.11.5 성남시 국공립 판교숲길 어린이집 위탁 선정</mark></li></ul><p>&nbsp;</p><p><strong>[비영리민간단체 자람의 설립취지]</strong></p><p>&nbsp;</p><p>&nbsp; *30여년간의 보육 현장의 보육의 경험을 토대로 향후의 보육 현장의 후배들에게 든든한 울타리로서 지원하는 위탁 사업</p><ul><li>104명의 회원이 함께 각자의 재능을 기부하고 참여</li></ul><p>&nbsp;</p><ul><li>놀이와 쉼이 있는 돌봄 , 우리동네 키움센터의 운영</li><li>사회복지원 사업</li><li>서울시 지역 특화 사업을 발굴 및 재능 기부</li></ul>', NULL, 0, 'esta', false, NULL, false, NULL, NULL, '2023-12-13 15:37:37.000', '2025-11-10 09:26:29.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (264, '2023년 사랑의 김장나눔 참여', '자원봉사지원', '<ul><li>2023년 사랑의 김장나눔</li><li>주최: 기능장애인</li><li>일시:2023년12월6일</li><li>봉사자:회원8명</li><li>장소: 일원에코파크</li></ul><figure class="image image_resized" style="width:16.73%;"><img src="/ckeditor/upload/2023/12/28/f44625bd-a51a-4a61-b611-ba544a5330b2.jpg"><figcaption>김장속을 듬북듬북---맛있는김치 탄생</figcaption></figure><p>&nbsp;</p><p>&nbsp;</p>', '/ckeditor/upload/2023/12/28/f44625bd-a51a-4a61-b611-ba544a5330b2.jpg', 5, 'news', false, NULL, false, 'k0421jm@naver.com', '권정문', '2023-12-28 10:59:11.000', '2023-12-28 10:59:11.000');
