insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (323, '우리동네 키움센터 봉사활동 신청에 대해 궁금해요!', NULL, '<p>안녕하십니까?&nbsp;</p><p>방금 &nbsp;<strong>비영리민간단체 자람</strong> 새내기 회원 가입 신청을 마친 송지민 입니다. &nbsp;&nbsp;</p><p><strong>&nbsp;“축하 합니다.” &nbsp;</strong></p><p><strong>수서역세권 다함께 키움센터 수탁기관</strong>으로 &nbsp;선정 !!!! &nbsp;<strong>&nbsp;</strong></p><p>&nbsp;</p><p>저의 근무지가 수서 역세권센터와 가까운 거리인 관계로.&nbsp;</p><p>출 퇴근시 지나가면서 궁금했는데….&nbsp;</p><p>기쁜 소식을 들었네요.&nbsp;</p><p>이에 영,유아 및 초등 돌봄에 봉사 활동을 신청 하려고 합니다.&nbsp;</p><p>방과후 &nbsp;2시간정도 (저녁 6시~8시)&nbsp;</p><p>시간 조율도 가능하답니다.&nbsp;</p><p>감사합니다.&nbsp;</p><p>&nbsp;</p><p>2024.8.10.&nbsp;</p><p>송지민 드림(010.7540.2121)</p>', NULL, 8, 'qna', true, NULL, false, 'winwincare@hanmail.net', '송지민', '2024-08-10 16:11:26.000', '2024-08-10 16:11:26.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (324, '비영리민간단체 자람 긴급 이사회', NULL, '<p>일시 : 2024.8.14 오후17시</p><p>장소: 자람</p><p>주요 내용 : 강남 9 호점 수서 역세권 다함께 키움 센터 (가칭) 종사자 공개 채용 관련 안건&nbsp;</p><p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 회의록 공개</p><figure class="image image_resized" style="width:67.31%;"><img src="/ckeditor/upload/2024/08/14/61e9ac67-7b25-4253-a06f-7d4d738167c7.jpg"></figure><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p>', NULL, 13, 'notice', false, NULL, false, 'k0421jm@naver.com', '권정문', '2024-08-14 21:31:48.000', '2024-08-14 21:31:48.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (325, '79주년 광복절을 기억 합니다', '청소년 태극기 만들기 참여', '<p>일시 :2024.8.14</p><p>장소;대청공원</p><p>주요 내용 : 나라사랑 프로젝트(어린이 태극기 만들기)</p><p>행사 참여 : 포토존 만들기 , 태극기 키트</p><p>&nbsp;</p><figure class="image image_resized" style="width:48.72%;"><img src="/ckeditor/upload/2024/08/14/12024f1c-260e-4a50-b314-6a3f2d30fbe7.png"></figure>', '/ckeditor/upload/2024/08/14/12024f1c-260e-4a50-b314-6a3f2d30fbe7.png', 7, 'news', false, NULL, false, 'k0421jm@naver.com', '권정문', '2024-08-14 21:35:40.000', '2024-08-14 21:35:40.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (326, '(공고) 강남9호점 수서역세권 다함께 키움센터 (가칭) 종사자 공개 채용 공고', NULL, '<p style="margin-left:4.0pt;">비영리민간단체 자람은 강남구청으로부터 수탁받아 아동들의 초등돌봄 사각지대를</p><p style="margin-left:4.0pt;">해소하기 위해 노력합니다.&nbsp;「<strong>강남9호점 수서역세권다함께키움센터(가칭)</strong>」에 근무할&nbsp;</p><p style="margin-left:4.0pt;">직원 채용 계획을 다음과 같이 공고 합니다.</p><p style="margin-left:4.0pt;">(자세한 내용은 첨부파일 참고 하세요.)</p>', NULL, 14, 'notice', false, NULL, false, 'k0421jm@naver.com', '권정문', '2024-08-14 21:40:37.000', '2024-08-14 21:40:37.000');
