insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (341, '대표소개', NULL, '<p><span class="text-huge">안녕하십니까?</span></p><p><span class="text-huge">비영리 민간 단체 자람 입니다.</span></p><p>&nbsp;</p><p><span class="text-huge">자람은</span></p><p><span class="text-huge">104명의 회원님들의 생각을 함께 모아서 설립한 단체 입니다.</span></p><p>&nbsp;</p><p><span class="text-huge">자람은 다음과 같은 목표를 실천 하고 자 합니다.</span></p><p>&nbsp;</p><p><span class="text-huge">○&nbsp;안심하고 맡길 보육 환경 조성과 초등 돌봄의 사각지대 해소</span></p><p><span class="text-huge">&nbsp;-&nbsp;학부모,&nbsp;교사,&nbsp;원장,&nbsp;지역 인사,&nbsp;마을 활동가 ,&nbsp;전문가의 구성으로 안심하고 맡길</span></p><p><span class="text-huge">&nbsp;보육 환경,&nbsp;사회적 경력 단절의 위기를 극복하도록 돕고,&nbsp;함께 운영하는 국 공립 직장 보육시설,&nbsp; 초등 돌봄의 위탁 사업 지원</span></p><p>&nbsp;</p><p><span class="text-huge">&nbsp;○&nbsp;민&nbsp;․&nbsp;관 협력 형 자람 프로그램 개발 &nbsp;( 지역맞춤 연계, 공익활동 지원사업)</span></p><p>&nbsp;</p><p><span class="text-huge">제 임기동안</span></p><p>&nbsp;</p><p><span class="text-huge">회원님들과 함께, 회원님들의 소중한 꿈을 이루어 가는 민간단체자람이</span></p><p><span class="text-huge">되도록 하겠습니다.</span></p><p>&nbsp;</p><p>&nbsp;</p>', NULL, 0, 'ceo', false, NULL, false, NULL, NULL, '2024-11-11 14:37:05.000', '2024-11-11 14:37:05.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (342, '대표소개', NULL, '<p>안녕하십니까?</p><p>비영리 민간 단체 자람 입니다.</p><p>&nbsp;</p><p>자람은</p><p>104명의 회원님들의 생각을 함께 모아서 설립한 단체 입니다.</p><p>&nbsp;</p><p>자람은 다음과 같은 목표를 실천 하고 자 합니다.</p><p>&nbsp;</p><p>○&nbsp;안심하고 맡길 보육 환경 조성과 초등 돌봄의 사각지대 해소</p><p>&nbsp;-&nbsp;학부모,&nbsp;교사,&nbsp;원장,&nbsp;지역 인사,&nbsp;마을 활동가 ,&nbsp;전문가의 구성으로 안심하고 맡길</p><p>&nbsp;보육 환경,&nbsp;사회적 경력 단절의 위기를 극복하도록 돕고,&nbsp;함께 운영하는 국 공립 직장 보육시설,&nbsp; 초등 돌봄의 위탁 사업 지원</p><p>&nbsp;</p><p>&nbsp;○&nbsp;민&nbsp;․&nbsp;관 협력 형 자람 프로그램 개발 &nbsp;( 지역맞춤 연계, 공익활동 지원사업)</p><p>&nbsp;</p><p>제 임기동안</p><p>&nbsp;</p><p>회원님들과 함께, 회원님들의 소중한 꿈을 이루어 가는 민간단체자람이</p><p>되도록 하겠습니다.</p><p>&nbsp;</p><p>&nbsp;</p>', NULL, 0, 'ceo', false, NULL, false, NULL, NULL, '2024-11-11 14:37:10.000', '2024-11-11 14:37:10.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (343, '대표소개', NULL, '<p>안녕하십니까?</p><p>비영리 민간 단체 자람 입니다.</p><p>&nbsp;</p><p>자람은</p><p>104명의 회원님들의 생각을 함께 모아서 설립한 단체 입니다.</p><p>&nbsp;</p><p>자람은 다음과 같은 목표를 실천 하고 자 합니다.</p><p>&nbsp;</p><p>○&nbsp;안심하고 맡길 보육 환경 조성과 초등 돌봄의 사각지대 해소</p><p>&nbsp;-&nbsp;학부모,&nbsp;교사,&nbsp;원장,&nbsp;지역 인사,&nbsp;마을 활동가 ,&nbsp;전문가의 구성으로 안심하고 맡길</p><p>&nbsp;보육 환경,&nbsp;사회적 경력 단절의 위기를 극복하도록 돕고,&nbsp;함께 운영하는 국 공립 직장 보육시설,&nbsp; 초등 돌봄의 위탁 사업 지원</p><p>&nbsp;</p><p>&nbsp;○&nbsp;민&nbsp;․&nbsp;관 협력 형 자람 프로그램 개발 &nbsp;( 지역맞춤 연계, 공익활동 지원사업)</p><p>&nbsp;</p><p>제 임기동안</p><p>&nbsp;</p><p>회원님들과 함께, 회원님들의 소중한 꿈을 이루어 가는 민간단체자람이</p><p><strong>되도록 하겠습니다.</strong></p><p>&nbsp;</p><p>&nbsp;</p>', NULL, 0, 'ceo', false, NULL, false, NULL, NULL, '2024-11-11 14:37:42.000', '2024-11-11 14:37:42.000');
