insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (372, '2024 임시이사회개최공고', NULL, '<p>비영리민간단체 자람 임시이사회 개최공고</p><ul><li>일시 : 2024.12.07</li><li>장소: 서울시 강남구 자곡로 11길28 (행복자곡다함께키움센터)</li><li>방법 : 대면 회의</li><li>참석 : 이사</li><li>이사회 의결사항</li></ul><p>- &nbsp;의안1 : 2024년 사업보고 및 2025년 사업계획</p><p>-의안2: 2024년 비영리민간단체 자람 감사 보고</p><p>-의안3 2025년 행복자곡다함께키움센터 예산안</p><p>-의안4 대표이사 변경건</p><p>-의안 2025년 총회 및 이사회 일정계획</p>', NULL, 7, 'notice', false, NULL, false, 'k0421jm@naver.com', '권정문', '2024-11-25 19:33:44.000', '2024-11-25 19:33:44.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (373, '임시 이사회 안건 상정', NULL, '<ul><li>성남시 다함께 &nbsp;돌봄 키움센터 위탁 신청 안건 상정 추가 이사회 개최</li><li>이사회 개최 안내</li></ul>', NULL, 7, 'notice', false, NULL, false, 'k0421jm@naver.com', '권정문', '2024-12-01 21:19:32.000', '2024-12-06 06:51:23.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (374, '2024년 비영리민간단체자람 감사보고 ', NULL, '<p>2024년 비영리 민간단체 감사보고서&nbsp;</p><p>&nbsp;</p><ul><li>조혜선 이사님,박정임감사님,이희란감사님 노고에 감사 드립니다.</li></ul><p>&nbsp;</p><figure class="image image_resized" style="width:55.65%;"><img src="/ckeditor/upload/2024/12/06/9b95b304-dadb-407e-b58a-b7fb3cfc1b97.png"></figure><p>&nbsp;</p><p>&nbsp;</p>', NULL, 3, 'notice', false, NULL, false, 'k0421jm@naver.com', '권정문', '2024-12-06 13:36:12.000', '2024-12-06 13:36:12.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (375, '산하시설퍼스티어고운어린이집 감사 보고', NULL, '<ul><li>2024년 산하 시설 지도 감사 결과 보고</li></ul><p>&nbsp; &nbsp; &nbsp; - 퍼스티어 고운 어린이집 감사</p><p>&nbsp; <img class="image_resized" style="width:65.53%;" src="/ckeditor/upload/2024/12/06/b5099de1-cbff-4253-bfd7-294e635f426d.png"></p>', NULL, 4, 'notice', false, NULL, false, 'k0421jm@naver.com', '권정문', '2024-12-06 13:38:00.000', '2024-12-06 13:38:00.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (376, '행복자곡다함께 키움센터 가정통신문', '12월 가정통신문', '<figure class="image image_resized" style="width:67.73%;"><img src="/ckeditor/upload/2024/12/06/2b321edf-272b-4513-a9dd-3c94baf3dc91.jpg"></figure>', '/ckeditor/upload/2024/12/06/2b321edf-272b-4513-a9dd-3c94baf3dc91.jpg', 4, 'news', false, NULL, false, 'k0421jm@naver.com', '권정문', '2024-12-06 13:42:24.000', '2024-12-06 13:42:24.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (377, '임시이사회 공고(추가)', NULL, '<p>임시이사회 공고(추가)</p><p>&nbsp;</p><p>의안이 추가되었습니다.&nbsp;</p><p>&nbsp;의안 : 성남시다함께돌봄센터 7호점 위탁신청</p><p>&nbsp;</p><p>많은 격려 부탁드립니다.</p>', NULL, 6, 'notice', false, NULL, false, 'k0421jm@naver.com', '권정문', '2024-12-10 12:04:47.000', '2024-12-10 12:04:47.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (378, '서울시공익활동 ', NULL, '<p>&nbsp; &nbsp; - 2025년 공익 활동 참여 안내</p><ul><li>비영리민간단체 자람 참여 : 자료 읽어 보시고 소중한 동참 바랍니다.</li></ul>', NULL, 5, 'notice', false, NULL, false, 'k0421jm@naver.com', '권정문', '2025-02-03 17:22:48.000', '2025-02-03 17:22:48.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (379, '행복자곡다함께키움센터', '2025년 활동 계획및 가정통신문', '<p>&nbsp; &nbsp; &nbsp;2025년 &nbsp;을사년 새해 복 많이 받으세요.</p><p>&nbsp;</p><ul><li>강남9호점 행복자고다함께 키움센터 2월 활동 계획 및 통신문 입니다.<img class="image_resized" style="width:93.36%;" src="/ckeditor/upload/2025/02/03/bee8d7dc-5737-4399-9aa3-95d100c5739a.jpg"></li></ul>', '/ckeditor/upload/2025/02/03/bee8d7dc-5737-4399-9aa3-95d100c5739a.jpg', 5, 'news', false, NULL, false, 'k0421jm@naver.com', '권정문', '2025-02-03 17:29:20.000', '2025-02-03 17:29:20.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (380, '산하시설 행복자곡다함께키움센터 실적보고', NULL, '<ul><li>서울시 아침돌봄 키움센터 운영</li><li>일시 : 2025.03.1~12.31</li><li>운영시간 : 오전7시~9시</li><li>주내용 : 학교등교 준비 및 간식 지도, 안전한 등교&nbsp;</li></ul><p><img class="image_resized" style="width:28.37%;" src="/ckeditor/upload/2025/02/13/af8084f2-c925-49dc-98ee-e4c848bf21d9.jpg"></p>', NULL, 5, 'notice', false, NULL, false, 'k0421jm@naver.com', '권정문', '2025-02-13 09:17:45.000', '2025-02-13 09:17:45.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (381, '강남9호점행복자곡다함께키움센터 아침돌교사모집공고', NULL, '<p>안녕하십니까?</p><p>비영리민간단체 자람에서 &nbsp;강남구로부터 수탁운영중인</p><p>강남9호점 행복자곡다함께 키움센터에서 아침돌봄 교사(시간제)를&nbsp;</p><p>&nbsp;긴급(공개채용)</p><p>으로 다음과 같이 채용 모집 합니다.</p><p>&nbsp;</p><p>자세한 채용 계획 내용은 &nbsp;첨부파일을 꼭 확인 부탁드립니다.</p><p>&nbsp;</p><ul><li>채용일자</li><li>채용방법</li><li>근로조건</li><li>제출 서류</li></ul><p>첨부 파일을 확인 해 주시기 바랍니다.</p><p>-표준이력서</p><p>-자기소개서</p><p>-개인정보동의서</p><p>&nbsp;</p><p>많은 관심과 접수 부탁드립니다.</p><p>&nbsp;</p><p>비영리민간단체 자람</p>', NULL, 3, 'notice', false, NULL, false, 'k0421jm@naver.com', '권정문', '2025-02-16 07:40:11.000', '2025-02-16 07:40:11.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (382, '행복자곡다함께키움센터아침돌봄긴급교사모집', NULL, '<ul><li>비영리민간단체 자람에서 서울형 아침돌봄 교사를 모집 합니다</li></ul><p>&nbsp;</p><p>&nbsp; - 모집요강 첨부 파일 꼭 확인 해주세요.</p>', NULL, 3, 'notice', false, NULL, false, 'k0421jm@naver.com', '권정문', '2025-03-29 06:51:28.000', '2025-03-29 06:51:28.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (383, '2025년 비영리민간단체 자람 임시 이사회 개최공고', NULL, '<p>이사님</p><p>안녕하십니까?</p><p>비영리민간단체 임시이사회롤 개최합니다.</p>', NULL, 3, 'notice', false, NULL, false, 'k0421jm@naver.com', '권정문', '2025-05-21 06:25:04.000', '2025-05-21 06:25:04.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (384, '2025년 임시 이사회 개최공고', NULL, '<p>안녕하십니까?</p><p>2025년 임시 이사회를 아래와 같이 공고 합니다.</p><p>이사님</p><p>바쁘시더라도 꼭 참석 부탁드립니다.</p><p>&nbsp;</p><ul><li>일시 : 2025년 5월28일 오전11시</li><li>장소: 행복자곡다함께 키움센터&nbsp;</li><li>의안 : 청담르엘 어린이집 위탁 신청&nbsp;</li><li>참석 대상 : 자람 이사님</li><li><img class="image_resized" style="width:35.23%;" src="/ckeditor/upload/2025/05/21/9099a892-4fba-4033-af67-a1bf1166ab86.jpg"></li></ul>', NULL, 3, 'notice', false, NULL, false, 'k0421jm@naver.com', '권정문', '2025-05-21 09:37:43.000', '2025-05-21 09:37:43.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (385, '2025년 비영리 민간단체 자람 이사회', '상반기 이사회', '<p>비영리 민간단체 자람 상반기 이사회 개최</p><figure class="image image_resized" style="width:51.92%;"><img src="/ckeditor/upload/2025/05/21/8fcd663c-76bb-49ae-bcf0-942df747cbee.png"></figure>', '/ckeditor/upload/2025/05/21/8fcd663c-76bb-49ae-bcf0-942df747cbee.png', 4, 'gallery', false, NULL, false, 'k0421jm@naver.com', '권정문', '2025-05-21 09:41:42.000', '2025-05-21 09:41:42.000');
