insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (390, '청담르엘 어린이집 위탁분과 TF', '청담르엘 어린이집 국공립 위탁 진행 결과', '<ul><li>비영리민간단체 자람 &nbsp;청담르엘어린이집 위탁 신청 (응원 합니다.)</li></ul><p>&nbsp; &nbsp; 1. 위탁준비 : 2025.5.2~2025.6.2</p><figure class="image image_resized" style="width:17.73%;"><img src="/ckeditor/upload/2025/06/24/2fac2718-73e0-4594-9685-e7b4802c7227.jpg"></figure><p>&nbsp; &nbsp; 2. 위탁서류 접수: 2025.6.2 (강남구청 보육지원과 접수 완료)</p><p>&nbsp;</p><p>&nbsp; &nbsp; &nbsp;3. 위탁 심의 : 2025.7.4일 예정</p><p>&nbsp;</p><p>&nbsp; &nbsp; &nbsp; * 회원님들의 응원과 격려 &nbsp;부탁드립니다.---</p><p>&nbsp;</p><p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;---- &nbsp;TF 팀 구성---- 운영</p><figure class="table" style="width:91.97%;"><table class="ck-table-resized"><colgroup><col style="width:12.13%;"><col style="width:26.3%;"><col style="width:22.51%;"><col style="width:24.11%;"><col style="width:14.95%;"></colgroup><tbody><tr><td><p style="text-align:center;">구분</p></td><td><p style="text-align:center;">인원</p></td><td><p style="text-align:center;">주내용</p></td><td><p style="text-align:center;">추진방향</p></td><td><p style="text-align:center;">기타</p></td></tr><tr><td>위탁분과</td><td>원장내정자,이사3인,감사,자문위원</td><td>-청담르엘 맞춤형&nbsp;</td><td>-위탁신청서 제작, 발표 리허설</td><td><ul><li>회원님들의 의견듣기</li></ul></td></tr><tr><td>복지분과.사회</td><td>이사 3명</td><td>-지역사회 협력</td><td>-지역연계 및 지원</td><td>회원들의 재능기부</td></tr></tbody></table></figure>', '/ckeditor/upload/2025/06/24/2fac2718-73e0-4594-9685-e7b4802c7227.jpg', 6, 'news', false, NULL, false, 'k0421jm@naver.com', '권정문', '2025-06-24 11:47:49.000', '2025-06-24 11:47:49.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (391, '청담르엘 어린이집 위탁분과 TF  최종 리허설 안내', NULL, '<ul><li>일시 : 2025.7.4 (오전11시)</li><li>장소: 행복자곡다함께키움센터</li><li>주내용: 청담르엘어린이집 심의 준비 (발표 리허설)</li><li>참석자: 누구나(이사님,회원님등)</li></ul><p>&nbsp;</p><p>&nbsp; &nbsp; 시간되시면 &nbsp;많은 참석 부탁 드립니다.</p>', NULL, 7, 'notice', false, NULL, false, NULL, NULL, '2025-06-24 12:43:50.000', '2025-06-24 12:43:50.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (392, '2025년 탄천 지역발전기금 주민사업 공모', NULL, '<p>안녕하십니까?</p><p>비영리민간단체 자람에서</p><p>탄천복지기금 주민 사업에 &nbsp;아래와 같이 공모 &nbsp;합니다.</p><p>&nbsp;</p><p>첨부 파일 참고 합니다.</p><p>&nbsp;</p><p>&nbsp;</p>', NULL, 8, 'notice', false, NULL, false, 'k0421jm@naver.com', '권정문', '2025-07-15 09:53:49.000', '2025-07-15 09:53:49.000');
