insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (397, '국공립 어린이집 원장 모집 공고', NULL, '<p style="margin-left:3.0pt;">&nbsp;</p><p style="margin-left:4.0pt;"><strong>&nbsp;비영리민간단체 자람에서는 의욕적이고 체계적으로 어린이집을 운영애 나갈 추직력 있는 원장(시설장)을 다음과 같이 공개 모집하오며 비젼과 역량을 갖춘 유능한 인재의 채용 계획을 다음과 같이 공고합니다.</strong></p><p style="margin-left:4.0pt;"><strong>&nbsp;</strong></p><p style="margin-left:4.0pt;">&nbsp;</p><p style="margin-left:4.0pt;text-align:center;"><strong>&nbsp;2025년9월1일</strong></p><p style="margin-left:4.0pt;text-align:center;"><strong>&nbsp;비영리민간단체 자람 대표이사</strong></p>', NULL, 15, 'notice', false, NULL, false, 'k0421jm@naver.com', '권정문', '2025-09-01 13:48:15.000', '2025-09-01 13:48:15.000');
