insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (421, '사업소개', NULL, '<h2 style="text-align:center;">&nbsp;</h2><h2 style="text-align:center;">🌼 <strong>아이의 하루가 반짝이는 곳, 퍼스티어고운어린이집</strong></h2><p style="text-align:center;">&nbsp;</p><p style="text-align:center;">퍼스티어고운어린이집은 <strong>안전하고 따뜻한 돌봄</strong>,<br>그리고 <strong>질 높은 교육 프로그램</strong>을 바탕으로<br>아이 한 명 한 명의 가능성을 아름답게 키워 나가는<br>국.공립 어린이집입니다.</p><p style="text-align:center;">&nbsp;</p><p style="text-align:center;">&nbsp;</p><p style="text-align:center;">&nbsp;</p><hr><h2 style="text-align:center;">&nbsp;</h2><h2 style="text-align:center;">✨ <strong>교육 철학</strong></h2><p style="text-align:center;">&nbsp;</p><p style="text-align:center;"><strong>🌱 즐겁게 배우는 아이</strong></p><p style="text-align:center;">아이 스스로 탐색하고 표현할 수 있는 배움 환경을 제공합니다.</p><p style="text-align:center;">&nbsp;</p><p style="text-align:center;">💛 <strong>따뜻하게 보살피는 공간</strong><br>안전·위생·정서를 모두 고려한 안정된 보육을 실천합니다.</p><p style="text-align:center;">&nbsp;</p><p style="text-align:center;">🌈 <strong>함께 성장하는 공동체</strong><br>가정과 어린이집이 함께 성장하는 열린 보육 문화를 지향합니다.</p><p style="text-align:center;">&nbsp;</p><p style="text-align:center;">&nbsp;</p><p style="text-align:center;">&nbsp;</p>', NULL, 0, 'biz-1', false, NULL, false, NULL, NULL, '2025-11-28 16:34:35.000', '2025-11-28 16:34:35.000');
