insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (425, '사업소개', NULL, '<p style="margin-left:0px;text-align:center;">초등생 우리아이 방과후 쉼과 놀이가 있는 공간</p><p style="margin-left:0px;text-align:center;">행복자곡키움센터입니다</p><p style="margin-left:0px;text-align:center;">​</p><p style="margin-left:0px;text-align:center;">02) 445- 4255 에 연락주세요</p><p style="margin-left:0px;text-align:center;">​</p><p style="margin-left:0px;text-align:center;">수서 행복주택 2단지 (208동 1층) 위치해 있습니다.</p><p style="margin-left:0px;text-align:center;">​<img class="image_resized" style="width:76.64%;" src="/ckeditor/upload/2026/04/10/148375c9-9144-49bc-9f23-54a6b0328c15.jpg"></p>', NULL, 0, 'biz-2', false, NULL, false, NULL, NULL, '2025-11-28 16:47:53.000', '2026-04-10 13:56:30.000');
