insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (428, '2025년 비영리민간단체 자람 이사회(제5회)', NULL, '<p>2025년 제 5차 이사회를 개최 합니다.</p><p>&nbsp;</p><p><strong>1.&nbsp;일시&nbsp;:&nbsp;<u>2025 .12. 18(목요일) &nbsp;오전&nbsp;11:00</u></strong></p><p><strong>&nbsp;2.&nbsp;장소&nbsp;:&nbsp;비영리민간단체 사무실&nbsp;</strong></p><p><strong>&nbsp;3.&nbsp;방법&nbsp;:&nbsp;대면 회의</strong></p><p><strong>&nbsp;4.&nbsp;참여&nbsp;:&nbsp;이사님&nbsp;</strong></p><p><strong>&nbsp;5.&nbsp;이사회 의결 사항</strong></p><p><strong>&nbsp;의안1&nbsp;행복자곡다함께 키움센터&nbsp;2025년 제2차 추경안</strong></p><p><strong>&nbsp;의안2&nbsp;행복자곡다함께 키움센ㅌ&nbsp;2026년 예산안&nbsp;</strong></p><p>&nbsp;</p><p><strong>일시 와 장소는 이사님들의 일정을 고려 하여 변경 될 수 있습니다.</strong></p>', NULL, 4, 'notice', false, NULL, false, 'k0421jm@naver.com', '권정문', '2025-12-12 12:00:55.000', '2025-12-12 12:00:55.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (429, '2025년 비영리민간단체 자람 제6차 이사회', NULL, '<p>비영리민간단체 자람 정기 이사회 개최 안내</p><p>&nbsp;</p><ul><li>일시 : 2025.12.27 토 13시</li><li>장소: 비영리민간단체 자람 사무실</li><li>참석대상 : 자람 이사님</li></ul><p>&nbsp; &nbsp;안건 : 서울형 키즈카페 서울식물원점 위탁 참여&nbsp;</p><figure class="image image_resized" style="width:30.32%;"><img src="/ckeditor/upload/2025/12/21/89a0217b-a7fb-49e9-9252-0048e1248665.hwp -사진001.jpg"></figure><p>&nbsp;</p>', NULL, 7, 'notice', false, NULL, false, 'k0421jm@naver.com', '권정문', '2025-12-21 19:09:17.000', '2025-12-21 19:09:17.000');
