insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (431, '개포국공립퍼스티어고운어린이집 전시회', '2025년아바와함께만드는 고운산타잔치', '<figure class="image"><img src="/ckeditor/upload/2025/12/23/d92ae71e-9b8c-4665-8128-6273e21ab0da.jpg"></figure>', '/ckeditor/upload/2025/12/23/d92ae71e-9b8c-4665-8128-6273e21ab0da.jpg', 1, 'gallery', false, NULL, false, 'k0421jm@naver.com', '권정문', '2025-12-23 17:54:38.000', '2025-12-23 17:54:38.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (432, '사업소개', NULL, '<h2 style="text-align:center;">🌼 <strong>아이의 하루가 반짝이는 곳, 퍼스티어고운어린이집</strong></h2><p style="text-align:center;">&nbsp;</p><p style="text-align:center;"><span class="text-big">퍼스티어고운어린이집은 <strong>안전하고 따뜻한 돌봄</strong>,</span><br><span class="text-big">그리고 <strong>질 높은 교육 프로그램</strong>을 바탕으로</span><br><span class="text-big">아이 한 명 한 명의 가능성을 아름답게 키워 나가는</span><br><span class="text-big">국.공립 어린이집입니다.</span></p><p style="text-align:center;">&nbsp;</p><hr><h2 style="text-align:center;">✨ <strong>교육 철학</strong></h2><p style="text-align:center;">&nbsp;</p><p style="text-align:center;"><span class="text-big"><strong>🌱 즐겁게 배우는 아이</strong></span></p><p style="text-align:center;"><span class="text-big">아이 스스로 탐색하고 표현할 수 있는 배움 환경을 제공합니다.</span></p><p style="text-align:center;">&nbsp;</p><p style="text-align:center;"><span class="text-big">💛 <strong>따뜻하게 보살피는 공간</strong></span><br><span class="text-big">안전·위생·정서를 모두 고려한 안정된 보육을 실천합니다.</span></p><p style="text-align:center;">&nbsp;</p><p style="text-align:center;"><span class="text-big">🌈 <strong>함께 성장하는 공동체</strong></span><br><span class="text-big">가정과 어린이집이 함께 성장하는 열린 보육 문화를 지향합니다.</span></p><p style="text-align:center;">&nbsp;</p><p style="text-align:center;">&nbsp;</p><p style="text-align:center;">&nbsp;</p>', NULL, 0, 'biz-1', false, NULL, false, NULL, NULL, '2025-12-23 17:55:14.000', '2025-12-23 17:55:14.000');
insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (433, '2026년도 강남9호점 아침돌봄 교사 모집공고', NULL, '<p>비영리민간단체 자람에서 2026년도 아침돌봄 교사를 모집 합니다.</p><p>&nbsp;</p><ul><li>근무 시작 : 2026.1.2~2026.12.31</li><li>근무 장소 : 강남9호점 행복자곡다함께키움센터 (수서행복주택 208동1층)</li><li>모집인원: 2명</li><li>문의사항 : 02-445-4255 ( 첨부파일 꼼꼼히 검토 부탁드립니다.)</li></ul>', NULL, 3, 'notice', false, NULL, false, 'k0421jm@naver.com', '권정문', '2025-12-26 13:29:45.000', '2025-12-26 13:29:45.000');
