insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (436, '2026년 이사회 개최 안내', NULL, '<p>&nbsp; &nbsp;</p><p><strong>&nbsp;비영리민간단체 자람이사회를&nbsp;</strong></p><p><strong>아래와 같이 개최 하오니 참석 해 주시길 바랍니다.</strong></p><p><strong>&nbsp;</strong></p><p><strong>&nbsp;■ &nbsp;일시&nbsp;: 2026년&nbsp;1월&nbsp;13일 화요일 오전11시&nbsp;</strong></p><p><strong>&nbsp;■ &nbsp;장소&nbsp;:&nbsp;비영리 민간단체 자람 사무실</strong></p><p><strong>&nbsp;■ &nbsp;참석&nbsp;:&nbsp;이사회</strong></p><p>&nbsp;</p><p><strong>안건1 :&nbsp;영등포구 국공립 어린이집 신규 위탁 참여</strong></p>', NULL, 5, 'notice', false, NULL, false, 'k0421jm@naver.com', '권정문', '2026-01-07 16:31:24.000', '2026-01-07 16:31:24.000');
