insert into jaram.posts (id, title, sub_title, content, main_image_url, view_count, page, is_private, password, is_deleted, author_id, author_name, created_at, updated_at) values (439, '2026년정기이사회', NULL, '<p>안녕하십니까?</p><p>비영리민간단체 자람 정기이사회를 안내 합니다.</p><p>&nbsp;</p><p>&nbsp;</p><ul><li>일시 : 2026년3월13일 오전 11시</li><li>장소 : 우제광 이사님 사무실(제일경노당)</li><li>회의 안건 : 2025년 산하 시설 결산 보고 및 승인 관련(행복자곡다함께 키움센터)</li><li>진행 과정 : 결산보고 공문 접수/결산자료 보고 제출됨(2026.3.5)</li></ul><p>&nbsp;</p><p>&nbsp; 비영림 민간 단체 자람</p>', NULL, 1, 'notice', false, NULL, false, 'k0421jm@naver.com', '권정문', '2026-03-06 06:05:18.000', '2026-03-06 06:05:18.000');
